(24, 1, 'groups', 'created_group', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> ha creat el node <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/dep-informatica/\">Dep. Informàtica</a>', '', 'https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/', 13, 0, '2014-09-19 17:01:17', 1, 0, 0, 0),
(34, 1, 'groups', 'activity_update', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> ha fet una actualització al node <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/educacio-emocional/\">Educació emocional</a>', 'Un gran vídeo per reflexionar...\n\nhttps://www.youtube.com/watch?v=wSNYYThX5-g', 'https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/', 14, 0, '2014-09-22 14:36:27', 0, 0, 0, 0),
(35, 1, 'groups', 'bbp_topic_create', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" rel=\"nofollow\">admin</a> ha començat <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/forum/topic/programa-redes-sobre-educacio-emocional/\">Programa Redes sobre educació emocional</a> tema en el fòrum <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/forum/\">Professorat</a>', 'Programa Redes sobre l\'educació emocional. Molt interessant. Per reflexionar.\n\n\n\n<span><img src=\"http://img.irtve.es/css/rtve.commons/rtve.header.footer/i/logoRTVEes.png\" alt=\"\" /></span> <a title=\"El aprendizaje social y emocional\" href=\"http://www.rtve.es/alacarta/videos/redes/redes-aprendizaje-social-20130526-2130-169/1839588/\"><strong>El aprendizaje social y emocional</strong></a>\n', 'https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/forum/topic/programa-redes-sobre-educacio-emocional/', 1, 206, '2014-09-22 14:40:28', 1, 0, 0, 0),
(36, 1, 'groups', 'bbp_topic_create', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" rel=\"nofollow\">admin</a> ha començat <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/forum/topic/indefensio-apresa/\">Indefensió apresa</a> tema en el fòrum <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/forum/\">Professorat</a>', 'Un dels objectius de la xarxa Nodes és oferir espais perquè els alumnes es pugin expressar fora de l\'aula. Pot ser una eina molt útil especialment pels alumnes que no destaquen pels seus resultats acadèmics i que tenen una baixa autoestima derivada d\'una indefensió apresa a l\'aula.\n\n', 'https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/forum/topic/indefensio-apresa/', 1, 207, '2014-09-22 14:46:13', 1, 0, 0, 0),
(38, 1, 'groups', 'activity_update', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> ha fet una actualització al node <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/rrr-reduccio-reutilitzacio-i-reciclatge/\">RRR – Reducció, Reutilització i Reciclatge</a>', '\n[bpfb_images]\n1_0-44155900-1411397838_koalarrr.jpg\n[/bpfb_images]', 'https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/', 18, 0, '2014-09-22 14:57:18', 0, 0, 0, 0),
(39, 1, 'groups', 'created_group', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> ha creat el node <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/papiroflexia/\">Papiroflexia</a>', '', 'https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/', 19, 0, '2014-09-22 15:08:11', 0, 0, 0, 0),
(40, 1, 'groups', 'bbp_topic_create', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" rel=\"nofollow\">admin</a> ha començat <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/papiroflexia/forum/topic/figura-n-1-la-granota/\">Figura n.1: La granota </a> tema en el fòrum <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/papiroflexia/forum/\">Papiroflexia</a>', 'Hola Noders! Qui s\'apunta a fer la granota? Aquí teniu les instruccions:\r\n\r\n[caption id=\"\" align=\"alignnone\" width=\"700\"]<img src=\"https://nodes-pre.educaciodigital.cat/masterzer/wp-content/uploads/usu16/2014/09/granota.png\" alt=\"Instruccions Granota\" width=\"700\" height=\"495\" /> Instruccions Granota[/caption]', 'https://nodes-pre.educaciodigital.cat/masterzer/nodes/papiroflexia/forum/topic/figura-n-1-la-granota/', 19, 211, '2014-09-22 15:11:13', 0, 0, 0, 0),
(41, 1, 'groups', 'activity_update', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> ha fet una actualització al node <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/papiroflexia/\">Papiroflexia</a>', 'Pengeu les vostres fotos amb la granota feta!', 'https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/', 19, 0, '2014-09-22 15:12:07', 0, 0, 0, 0),
(43, 1, 'groups', 'activity_update', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> ha fet una actualització al node <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/cinema/\">Cinema</a>', 'Hola Noders! Avui des del node de cinema volem compartir un curtmetratge molt xulo, ple de fantasia.\n\nhttps://www.youtube.com/watch?v=p-yPn2FxxJw', 'https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/', 15, 0, '2014-09-22 15:33:34', 0, 0, 0, 0),
(45, 1, 'groups', 'activity_update', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> ha fet una actualització al node <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/fotografia/\">Fotografia</a>', 'Una foto que vaig fer a Menorca, que us suggereix? \n[bpfb_images]\n1_0-42209200-1411400780_menorca_jmeler.jpg\n[/bpfb_images]', 'https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/', 17, 0, '2014-09-22 15:46:20', 0, 0, 0, 0),
(47, 1, 'groups', 'activity_update', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> ha fet una actualització al node <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/educacio-emocional/\">Educació emocional</a>', 'Bon dia Noders! Avui us compartim un inquietant curtmetratge que ens ha de fer reflexionar sobre l’individualisme… és molt xulo… i fins i tot va guanyar un Oscar!\n\nhttps://www.youtube.com/watch?v=pRUGRPKRAWs', 'https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/', 14, 0, '2014-09-22 15:59:20', 0, 0, 0, 0),
(48, 1, 'groups', 'bbp_topic_create', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" rel=\"nofollow\">admin</a> ha començat <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/forum/topic/documental-sobre-educacio-emocional/\">Documental sobre educació Emocional</a> tema en el fòrum <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/forum/\">Professorat</a>', 'Molt recomanable:\nhttps://www.youtube.com/watch?v=PQE4WqQSOcQ', 'https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/forum/topic/documental-sobre-educacio-emocional/', 1, 216, '2014-09-22 16:54:13', 1, 0, 0, 0),
(50, 1, 'groups', 'bp_doc_edited', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> edited the doc <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/docs/document-a-google-drive/\">Document a Google Drive</a> in the group <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/\">Professorat</a>', '', 'https://nodes-pre.educaciodigital.cat/masterzer/docs/document-a-google-drive/', 1, 230, '2014-10-23 15:07:51', 1, 0, 0, 0),
(52, 1, 'groups', 'bp_doc_created', '<a href=\"https://nodes-pre.educaciodigital.cat/masterzer/membres/admin/\" title=\"admin\">admin</a> created the doc <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/docs/professorat-2/\">Professorat</a> in the group <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/nodes/professorat/\">Professorat</a>', '', 'https://nodes-pre.educaciodigital.cat/masterzer/docs/professorat-2/', 1, 236, '2014-10-23 15:14:55', 1, 0, 0, 0),
