(1, 'sha-publicat-un-article-nou-posttitle', 'S\'ha publicat un article nou:  {{POSTTITLE}}', 'post_notification', NULL, NULL, NULL, NULL, 'Admin', 'a8000006@xtec.cat', 'Admin', 'a8000006@xtec.cat', '##post:29##', '1', 459, 1, 'a:1:{s:15:\"list_conditions\";a:1:{i:0;a:1:{i:0;a:3:{s:5:\"field\";s:10:\"_lists__in\";s:8:\"operator\";s:2:\"is\";s:5:\"value\";a:1:{i:0;s:1:\"1\";}}}}}', '2019-05-13 07:44:20', '2026-03-26 15:22:14', '0000-00-00 00:00:00'),
(2, 'envia-un-missatge-de-benvinguda-quan-algu-se-subscriu', 'Envia un missatge de benvinguda quan algú se subscriu', 'workflow', 1, 'workflow', NULL, '', 'ZER L&#039;Arany', 'a8000010@xtec.cat', 'ZER L&#039;Arany', 'a8000010@xtec.cat', '', '', 0, 1, NULL, '2026-03-26 15:22:11', '2026-03-26 15:22:11', NULL),
(3, 'envia-el-missatge-de-confirmacio', 'Envia el missatge de confirmació', 'workflow_email', 2, 'workflow', 'Welcome to {{SITENAME}}', '<p>Hi {{NAME}},</p>\n<p>Just wanted to send you a quick note...</p>\n<p>Thank you for joining the awesome {{SITENAME}} tribe.</p>\n<p>Only valuable emails from me, promise!</p>\n<p>Thanks!</p>\n', 'ZER L&#039;Arany', 'a8000010@xtec.cat', 'ZER L&#039;Arany', 'a8000010@xtec.cat', '', '', 0, 1, 'a:3:{s:20:\"enable_open_tracking\";s:2:\"no\";s:20:\"enable_link_tracking\";s:2:\"no\";s:11:\"attachments\";a:0:{}}', '2026-03-26 15:22:11', '2026-03-26 15:22:11', NULL),
(4, 'notifica-ladministrador-a-quan-algu-se-subscriu', 'Notifica l\'administrador/a quan algú se subscriu', 'workflow_email', 3, 'workflow', 'Thanks!', '<p>Hi {{NAME}},</p>\n<p>Just one more step before we share the awesomeness from {{SITENAME}}!</p>\n<p>Please confirm your subscription by clicking on this link:</p>\n<p>{{LINK}}</p>\n<p>Thanks!</p>\n', 'ZER L&#039;Arany', 'a8000010@xtec.cat', 'ZER L&#039;Arany', 'a8000010@xtec.cat', '', '', 0, 0, 'a:3:{s:20:\"enable_open_tracking\";s:2:\"no\";s:20:\"enable_link_tracking\";s:2:\"no\";s:11:\"attachments\";a:0:{}}', '2026-03-26 15:22:11', '2026-03-26 15:22:11', NULL),
(5, 'notifica-als-administradors-cada-vegada-que-senvii-un-butlleti', 'Notifica als administradors cada vegada que s\'enviï un butlletí', 'workflow_email', 4, 'workflow', 'One more contact joins our tribe!', '<p>Hi,</p>\n<p>Your friendly Email Subscribers notification bot here!</p>\n<p>{{NAME}} ({{EMAIL}}) joined our tribe just now.</p>\n<p>Which list/s? {{LIST}}</p>\n<p>If you know this person, or if they are an influencer, you may want to reach out to them personally!</p>\n<p>Later...</p>\n', 'ZER L&#039;Arany', 'a8000010@xtec.cat', 'ZER L&#039;Arany', 'a8000010@xtec.cat', '', '', 0, 0, 'a:3:{s:20:\"enable_open_tracking\";s:2:\"no\";s:20:\"enable_link_tracking\";s:2:\"no\";s:11:\"attachments\";a:0:{}}', '2026-03-26 15:22:11', '2026-03-26 15:22:12', NULL),
(6, 'campaign-sent-from-sitename', 'Campaign sent from {{SITENAME}}', 'workflow_email', 5, 'workflow', 'Campaign sent from {{SITENAME}}', '<p>Hi Admin,</p>\n<p>Cron URL has been triggered successfully on {{DATE}} for the email \'{{SUBJECT}}\'. And it sent email to {{COUNT}} recipient(s).</p>\n<p>Best,<br />\nZER L&#039;Arany</p>\n', 'ZER L&#039;Arany', 'a8000010@xtec.cat', 'ZER L&#039;Arany', 'a8000010@xtec.cat', '', '', 0, 1, 'a:3:{s:20:\"enable_open_tracking\";s:2:\"no\";s:20:\"enable_link_tracking\";s:2:\"no\";s:11:\"attachments\";a:0:{}}', '2026-03-26 15:22:11', NULL, NULL);
