(3, 'Subscription form with logo', '<div class=\"gjs-cell\"></div><div id=\"ib2a\" class=\"es-form-field-container\"><div id=\"i0fw6\" class=\"gjs-cell\"><img src=\"https://nodes-pre.educaciodigital.cat/masterzer/wp-content/plugins/email-subscribers/lite/admin/images/white_mail_icon.png\" width=\"300\" height=\"200\" id=\"iarpk\"/></div><div class=\"gjs-row\"></div><p id=\"it9g\">Subscribe To Our Newsletter</p><div class=\"gjs-row\"><div id=\"i9kx\" class=\"gjs-cell\"><input type=\"email\" required class=\"es-email\" name=\"esfpx_email\" autocomplete=\"email\" placeholder=\"Email Address\" id=\"esfpx_email_bce83274f66ad\"/></div></div><div class=\"gjs-row\"><div id=\"imc2g\" class=\"gjs-cell\"><input type=\"submit\" name=\"submit\" value=\"Subscribe\" required id=\"ivrac\"/></div></div></div>', 'a:10:{s:11:\"editor_type\";s:13:\"drag-and-drop\";s:10:\"form_style\";s:0:\"\";s:15:\"dnd_editor_data\";s:2989:\"[{\"classes\":[{\"name\":\"gjs-cell\",\"private\":1}]},{\"type\":\"form-field-container\",\"style\":{\"padding-top\":\"30px\",\"padding-right\":\"10px\",\"padding-bottom\":\"50px\",\"padding-left\":\"10px\",\"width\":\"450px\",\"background-color\":\"#2a0555\"},\"classes\":[\"es-form-field-container\"],\"attributes\":{\"style\":\"padding-top:30px;padding-right:10px;padding-bottom:50px;padding-left:10px;width:450px;background-color:#2a0555;\",\"id\":\"ib2a\"},\"components\":[{\"style\":{\"text-align\":\"center\"},\"classes\":[{\"name\":\"gjs-cell\",\"private\":1}],\"attributes\":{\"style\":\"text-align:center;\",\"id\":\"i0fw6\"},\"components\":[{\"type\":\"image\",\"style\":{\"height\":\"80px\",\"en\":\"1\",\"width\":\"100px\"},\"attributes\":{\"src\":\"http://localhost/igwp_setup/wp-content/uploads/2024/10/mail-vector-icon-white-illustration-260nw-575365351-removebg-preview.png\",\"width\":\"300\",\"height\":\"200\",\"id\":\"iarpk\",\"style\":\"height:80px;en:1;width:100px;\"}}]},{\"classes\":[{\"name\":\"gjs-row\",\"private\":1}]},{\"tagName\":\"p\",\"type\":\"te