INSERT INTO `wp_ig_workflows` (`id`, `name`, `title`, `trigger_name`, `trigger_options`, `rules`, `actions`, `status`, `type`, `priority`, `meta`, `created_at`, `updated_at`) VALUES
(1, 'envia-un-missatge-de-benvinguda-quan-algu-se-subscriu', 'Envia un missatge de benvinguda quan algú se subscriu', 'ig_es_user_subscribed', '', '', 'a:1:{i:0;a:5:{s:11:\"action_name\";s:16:\"ig_es_send_email\";s:13:\"ig-es-send-to\";s:9:\"{{EMAIL}}\";s:19:\"ig-es-email-subject\";s:23:\"Welcome to {{SITENAME}}\";s:19:\"ig-es-email-content\";s:189:\"<p>Hi {{NAME}},</p>\n<p>Just wanted to send you a quick note...</p>\n<p>Thank you for joining the awesome {{SITENAME}} tribe.</p>\n<p>Only valuable emails from me, promise!</p>\n<p>Thanks!</p>\n\";s:26:\"ig-es-tracking-campaign-id\";i:3;}}', 1, 1, 0, 'a:1:{s:11:\"when_to_run\";s:11:\"immediately\";}', '2026-03-26 15:22:11', '2026-03-26 15:22:11'),
(2, 'envia-el-missatge-de-confirmacio', 'Envia el missatge de confirmació', 'ig_es_user_unconfirmed', '', '', 'a:1:{i:0;a:5:{s:11:\"action_name\";s:16:\"ig_es_send_email\";s:13:\"ig-es-send-to\";s:9:\"{{EMAIL}}\";s:19:\"ig-es-email-subject\";s:7:\"Thanks!\";s:19:\"ig-es-email-content\";s:194:\"<p>Hi {{NAME}},</p>\n<p>Just one more step before we share the awesomeness from {{SITENAME}}!</p>\n<p>Please confirm your subscription by clicking on this link:</p>\n<p>{{LINK}}</p>\n<p>Thanks!</p>\n\";s:26:\"ig-es-tracking-campaign-id\";i:4;}}', 1, 1, 0, 'a:1:{s:11:\"when_to_run\";s:11:\"immediately\";}', '2026-03-26 15:22:11', '2026-03-26 15:22:11'),
(3, 'notifica-ladministrador-a-quan-algu-se-subscriu', 'Notifica l\'administrador/a quan algú se subscriu', 'ig_es_user_subscribed', '', '', 'a:1:{i:0;a:5:{s:11:\"action_name\";s:16:\"ig_es_send_email\";s:13:\"ig-es-send-to\";s:17:\"a8000010@xtec.cat\";s:19:\"ig-es-email-subject\";s:33:\"One more contact joins our tribe!\";s:19:\"ig-es-email-content\";s:282:\"<p>Hi,</p>\n<p>Your friendly Email Subscribers notification bot here!</p>\n<p>{{NAME}} ({{EMAIL}}) joined our tribe just now.</p>\n<p>Which list/s? {{LIST}}</p>\n<p>If you know this person, or if they are an influencer, you may want to reach out to them personally!</p>\n<p>Later...</p>\n\";s:26:\"ig-es-tracking-campaign-id\";i:5;}}', 0, 1, 0, 'a:1:{s:11:\"when_to_run\";s:11:\"immediately\";}', '2026-03-26 15:22:11', '2026-03-26 15:22:11'),
(4, 'notifica-als-administradors-cada-vegada-que-senvii-un-butlleti', 'Notifica als administradors cada vegada que s\'enviï un butlletí', 'ig_es_campaign_sent', '', '', 'a:1:{i:0;a:5:{s:11:\"action_name\";s:16:\"ig_es_send_email\";s:13:\"ig-es-send-to\";s:17:\"a8000010@xtec.cat\";s:19:\"ig-es-email-subject\";s:31:\"Campaign sent from {{SITENAME}}\";s:19:\"ig-es-email-content\";s:187:\"<p>Hi Admin,</p>\n<p>Cron URL has been triggered successfully on {{DATE}} for the email \'{{SUBJECT}}\'. And it sent email to {{COUNT}} recipient(s).</p>\n<p>Best,<br />\nZER L&#039;Arany</p>\n\";s:26:\"ig-es-tracking-campaign-id\";i:6;}}', 0, 1, 0, 'a:1:{s:11:\"when_to_run\";s:11:\"immediately\";}', '2026-03-26 15:22:11', '2026-03-26 15:22:12');
