(80, 'widget_text', 'a:12:{i:1;a:0:{}i:2;a:4:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:431:\"<a class=\"twitter-timeline\" href=\"https://twitter.com/institut_larany\" data-widget-id=\"512216549814333440\">Tuits de @institut_larany</a>\r\n<script>!function(d,s,id){var js,fjs=d.getElementsByTagName(s)[0],p=/^http:/.test(d.location)?\'http\':\'https\';if(!d.getElementById(id)){js=d.createElement(s);js.id=id;js.src=p+\"://platform.twitter.com/widgets.js\";fjs.parentNode.insertBefore(js,fjs);}}(document,\"script\",\"twitter-wjs\");</script>\";s:6:\"filter\";s:0:\"\";s:10:\"conditions\";a:2:{s:6:\"action\";s:4:\"show\";s:5:\"rules\";a:4:{i:0;a:2:{s:5:\"major\";s:8:\"category\";s:5:\"minor\";s:2:\"59\";}i:1;a:2:{s:5:\"major\";s:8:\"category\";s:5:\"minor\";s:2:\"68\";}i:2;a:2:{s:5:\"major\";s:8:\"category\";s:5:\"minor\";s:2:\"70\";}i:3;a:2:{s:5:\"major\";s:8:\"category\";s:5:\"minor\";s:2:\"69\";}}}}i:3;a:4:{s:5:\"title\";s:15:\"Blog de l\'AMPA \";s:4:\"text\";s:322:\"Aquí podeu trobar les últimes noticies de l\'AMPA.\r\n\r\nPer contactar amb l\'AMPA: \r\n\r\n<strong>Email:</strong>\r\nampa@zer-larany.cat\r\n\r\n<strong>Telèfon:</strong>\r\n123 45 67 89\r\n\r\nSi voleu saber qui forma part de l\'AMPA i les seves funcions feu clic <a href=\"https://nodes-pre.educaciodigital.cat/masterzer/ampa/\">aquí</a>. \";s:6:\"filter\";s:1:\"1\";s:10:\"conditions\";a:2:{s:6:\"action\";s:4:\"show\";s:5:\"rules\";a:4:{i:0;a:2:{s:5:\"major\";s:8:\"category\";s:5:\"minor\";s:2:\"31\";}i:1;a:2:{s:5:\"major\";s:8:\"category\";s:5:\"minor\";s:2:\"78\";}i:2;a:2:{s:5:\"major\";s:8:\"category\";s:5:\"minor\";s:2:\"77\";}i:3;a:2:{s:5:\"major\";s:8:\"category\";s:5:\"minor\";s:2:\"76\";}}}}i:19;a:3:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:0:\"\";s:6:\"filter\";s:0:\"\";}i:21;a:4:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:145:\"<i class=\"fa fa-file-text-o fa-5x\"></i>\r\n\r\nAquí podeu trobar els documents normatius i de referència comuns a totes les escoles de la ZER. \r\n\r\n\";s:6:\"filter\";s:1:\"1\";