(41549, 'ig_es_custom_admin_notice_show_wp_cron', 'a:3:{s:3:\"url\";s:24:\"https://www.icegram.com/\";s:7:\"include\";s:107:\"/dades/html/wordpress/wp-content/plugins/email-subscribers/lite/includes/notices/views/ig-es-bfcm-offer.php\";s:4:\"html\";s:1210:\"<div class=\"notice notice-warning\" style=\"background-color: #FFF;\"><p style=\"letter-spacing: 0.6px;\">El cron del WordPress no està activat al vostre lloc. Les notificacions de correu electrònic de l\'extensió de subscriptors de correu electrònic no s’enviaran automàticament. <a href=\"https://www.icegram.com/documentation/how-to-enable-the-wordpress-cron/?utm_medium=enable_wordpress_cron&utm_source=in_app&utm_campaign=view_admin_notice\" target=\"_blank\" >Així el podeu activar.</a><br/>O planifiqueu Cron a <a href=\"https://www.icegram.com/documentation/es-how-to-schedule-cron-emails-in-cpanel/?utm_source=schedule_cron_in_cpanel&utm_medium=in_app&utm_campaign=view_admin_notice\" target=\"_blank\">cPanel</a><br/>Or use <strong><a href=\"https://www.icegram.com/documentation/es-how-to-schedule-cron-emails-in-cpanel/?utm_source=schedule_cron_in_cpanel&utm_medium=in_app&utm_campaign=view_admin_notice\" target=\"_blank\">Icegram Express Pro</a></strong> for automatic Cron support<a style=\"float:right\" class=\"es-admin-btn es-admin-btn-secondary \" href=\"/masterzer/wp-admin/admin-ajax.php?es_dismiss_admin_notice=1&#038;option_name=wp_cron_notice&#038;_wpnonce=031617b977\">Val, ho he entès!</a></p></div>\";}', 'auto'),
