(396, 1, '2015-07-23 15:26:30', '2015-07-23 14:26:30', 'En aquesta secció hi podeu incloure:\r\n<ul>\r\n	<li>Breu descripció de l\'escola (nombre de grups, alumnes etc.)</li>\r\n	<li>Història</li>\r\n	<li>Organigrama</li>\r\n	<li>Galeria de fotografies (recomanat Carrusel amb Picasa)</li>\r\n</ul>\r\n&nbsp;', 'Qui som', '', 'publish', 'closed', 'closed', '', 'qui-som', '', '', '2015-10-27 10:08:52', '2015-10-27 09:08:52', '', 268, 'https://nodes-pre.educaciodigital.cat/masterzer/?page_id=396', 10, 'page', '', 0),
